window.__QUIZ_DATA__=[{"id":"objective>Geography>2013>1","subject":"Geography","year":"2013","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"What is the approximate distance by rail from Kabe Odu?","images":["data:image/png;base64,"],"options":{"A":"9.0 km","B":"8.0 km","C":"6.0 km","D":"4.0 km"},"answer":"C","explanation":"From the scale of the map, 2km is equivalent to 1.8cm. It implies that 1km is equivalent to 0.9cm. After using a thread to measure the length of path from Kabe to Odu, we have a length of 5.4cm which is equivalent to 6.0km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>2","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The direction of ODU from Sofia is","images":["data:image/png;base64,"],"options":{"A":"southwest","B":"east","C":"northwest","D":"south"},"answer":"A","explanation":"\u21d2 the direction of ODU from Sofia is Southwest","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>3","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the scale of the map expressed as Representative Fraction (R.F.)?","images":["data:image/png;base64,"],"options":{"A":"1 : 25,000","B":"1 : 50,000","C":"1 : 100,000","D":"1 : 250,000"},"answer":"C","explanation":"The scale of the map in representative fraction is 1:100,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>4","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is the name of the relief feature lettered W?","images":["data:image/png;base64,"],"options":{"A":"Headland","B":"Conical hill","C":"Plateau","D":"Lake"},"answer":"B","explanation":"The relief feature labelled W is a conical hill. A conical hill is a steep, isolated hill or small mountain with a roughly conical or pointed shape. It is typically formed by natural processes such as erosion, volcanic activity, or deposition. The defining feature of a conical hill is its tapering, symmetrical form, where the slope gradually becomes steeper toward the peak, resembling a cone.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>5","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The symbol \u2206 1030 represents a","images":[],"options":{"A":"benchmark","B":"boundary pillar","C":"trigonometrical station","D":"beacon"},"answer":"C","explanation":"The feature \u2206 1030 represents a trigonometrical station","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>6","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following industries could be set up in Yapo?","images":[],"options":{"A":"Saw milling","B":"Fruit canning","C":"Meat canning","D":"Oil refining"},"answer":"A","explanation":"Yapo has so many forest areas, hence a saw mill industry can be set up in this region.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>7","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The long stretch of highland to the northeastern part of the map is a","images":[],"options":{"A":"caldera","B":"canyon","C":"ridge","D":"gorge"},"answer":"C","explanation":"The ridge is the longest of highland to the northeastern part of the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>8","subject":"Geography","year":"2013","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which of the following areas is best suited for sugar cane cultivation?","images":[],"options":{"A":"Area around Segot","B":"Area south of Yapo","C":"The lowland of the northeast","D":"The forest area"},"answer":"B","explanation":"The area South of Yapo is best suited for sugar cane cultivation","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>9","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"From which of the following settlements is ODU visible?","images":[],"options":{"A":"Gamb","B":"Segot","C":"Yapo","D":"Sofia"},"answer":"C","explanation":"ODU settlements  is visible from Yapo. Other settlements are not.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>10","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"ODU is most likely to be important trading centre because it is","images":[],"options":{"A":"a nodal centre","B":"a fish canning town","C":"a mining town","D":"close to a port"},"answer":"A","explanation":"ODU is actually a nodal settlement, hence it is going to be an important trading centre.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>11","subject":"Geography","year":"2013","type":"Objective","topic":"THE SOLAR SYSTEM","question":"Which of the following planets is the fathest from the sun in the solar system?","images":[],"options":{"A":"Mars","B":"Mercury","C":"Neptune","D":"Pluto"},"answer":"D","explanation":"Pluto is the farthest planet from the sun in the solar system      M1 \u2192 Mercury   V \u2192 Venus   E \u2192 Earth   M2 \u2192 Mars   J \u2192 Jupiter   S \u2192 Saturn   U \u2192 Uranus   N \u2192 Neptune   P \u2192 Pluto     This arrangement is in order of decreasing closeness to the sun","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>12","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What will be the local time in Nigeria 15oE when the time is 7.00 p.m. in town Y 30oW?","images":[],"options":{"A":"9.00 a.m","B":"10.00 p.m","C":"10.36 a.m","D":"10.36 p.m"},"answer":"B","explanation":"Longitude of Nigeria (15oE)  Longitude of Town Y (30oW) at 7:00 pm   \u21d2 Longitudinal difference = 15o + 30o = 45o    Recall: 1o = 4 minutes   45o = x   \u21d2 x = 180 minutes = 3 hours   We are going to add 3 hours to 7.00 pm   \u21d2 Nigeria will be at 10.00 pm","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>13","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance between two places if one is located on 11oN and the other on 5oS on the same longitude?","images":[],"options":{"A":"211 km","B":"1,110 km","C":"1,776 km","D":"1,976 km"},"answer":"C","explanation":"We are given that the two locations are on the same longitude, which means we are going to apply     D=\u03b8360x2\u03c0R----------x    \u03b8 = longitudinal difference   R = Radius of the earth   \u03b8 = 11 + 5 = 16o ; R = 6370 km     \u21d216360x227x2x6370km=D=1,776km","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>14","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The horizontal displacement of blocks of the earth's crust along a fult plane is called","images":[],"options":{"A":"tear faulting","B":"reverse faulting","C":"normal faulting","D":"isostatic adjustment"},"answer":"C","explanation":"Normal faulting is the horizontal displacement of blocks of the earth's crust along a fault plane.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2013>15","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The section of the external structure of the eath that supports life is the","images":[],"options":{"A":"biophere","B":"atmosphere","C":"lithosphere","D":"barysphere"},"answer":"A","explanation":"Biosphere is the section of the external surface of the earth that supports life. We may also describe it as living portion of the earth.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>16","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following are examples of metamorphic rocks?","images":[],"options":{"A":"Basalt and gabbro","B":"Genesis and quartzite","C":"Granite and gabbro","D":"Gnesis and basalt"},"answer":"B","explanation":"It should be noted that Gneisis and Quartzite are morphic rocks.    \u21d2 Gneiss is a common and widely distributed metamorphic rocks having bands or veins, but schistose.  \u21d2 Quartzite is a metamorphic rock consisting of interlocking grains of quartz.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>17","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The name of the volcanic rock which often forms the root of fold mountain is called","images":[],"options":{"A":"Batholith","B":"Dyke","C":"Sill","D":"Lopolith"},"answer":"A","explanation":"Batholith is the name of the volcanic rock which often forms the root of fold mountains   We may also  say that \"batholith\" is a large irregular mass of intrusive igneous rock that has melted or forced itself into surrounding strata.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2013>18","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is the most important weathering process in karsh regions?","images":[],"options":{"A":"Hydrolysis","B":"Oxidation","C":"Hydration","D":"Carbonation"},"answer":"D","explanation":"Carbonation is the most important weathering process in karst regions. Karst topography is a landscape formed from the dissolution of soluble rocks such as limestone, dolomite, and gypsum. It is characterized by underground drainage systems with sinkholes and caves. Carbonation weathering is the process by which rainwater mixes with carbon dioxide in the air to form carbonic acid. This acid reacts with minerals in the rock and dissolves them, leading to features such as caves and sinkholes. Hydrolysis is a chemical weathering process that involves water. Oxidation is a chemical reaction that occurs when oxygen reacts with another substance. Hydration is the process by which water is added to a substance.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>19","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following mass wasting wasting process results in curved tree trunks and leaning telegraph poles?","images":[],"options":{"A":"Rock fall","B":"Earth flow","C":"Soil creep","D":"Mud flow"},"answer":"A","explanation":"Rock fall, a natural and dynamic geologic process involving the detachment and rapid downward movement of rock.     It results in curved tree trunks and leaning telegraph poles.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>20","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following are circular depressions formed on the bed of a river in its upper course by pebbles carried by the river?","images":[],"options":{"A":"Potholes","B":"Plunge pools","C":"Gorges","D":"Rapids"},"answer":"C","explanation":"Gorges are circular depressions formed on the river bed in its upper course by pepples carried by the river","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>21","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Through what process are rift valleys formed?","images":[],"options":{"A":"Folding","B":"Erosion","C":"Faulting","D":"Weathering"},"answer":"C","explanation":"Rift valleys are formed through a process known as faulting. Faulting is a geological process that involves the movement of blocks of the earth's crust which leads to cracks or faults. When tensional forces pull the crust apart, it breaks along parallel faults, and the block of crust between them sinks down into the mantle, forming a rift valley.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>22","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The process by which rocks are disintegrated by physical and chemical means in situ is known as","images":[],"options":{"A":"decompositions","B":"erosion","C":"transportation","D":"weathering"},"answer":"D","explanation":"The process by which rocks are disintegrated by physical and chemical means in situ is known as weathering. Weathering involves the breaking down or disintegration of rocks and minerals on the earth's surface, without moving them around. This can occur through physical processes (like temperature changes or freeze-thaw action), chemical processes (like reaction with water, air or other substances), or biological activity (like the action of plants or animals).","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>23","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following is a feature commonly found in the youthful stage of a river?","images":[],"options":{"A":"Leave","B":"Delta","C":"Oxbow lake","D":"Interlocking spur"},"answer":"D","explanation":"In the youthful stage of a river, the river has a lot of energy and a steep gradient. As a result, it erodes its bed and banks vertically to form a narrow, V-shaped valley. This process often results in the formation of interlocking spurs, which are protruding ridges that the river winds around. Therefore, the correct answer is 'Interlocking spur'.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>24","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The shallow part of the sea adjoining the coast is called","images":[],"options":{"A":"continental shelf","B":"continental slope","C":"oceanic island","D":"oceanic plateau"},"answer":"A","explanation":"The shallow part of the sea adjoining the coast is called the continental shelf. It is an underwater landmass which extends from a continent, resulting in an area of relatively shallow water known as a shelf sea. Therefore, the correct answer is 'continental shelf'.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>25","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Most warm ocean currents flow","images":[],"options":{"A":"in tropical seas","B":"from the Equator","C":"to the Equator","D":"in high latitudes"},"answer":"B","explanation":"As ocean currents flow along the edges of continents, they affect the temperature of the coastal region. Along the coast of the U.S, the Gulf stream carries warm water from the equatorial region to the North.     Atlantic Ocean, keeping the southeast coast relatively warm","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>26","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Hail, fog, dew and frost are all forms of","images":[],"options":{"A":"rainfall","B":"cloud","C":"water vapour","D":"precipitation"},"answer":"D","explanation":"Hail, fog, dew and frost are all forms of precipitation. Precipitation is any product of the condensation of atmospheric water vapor that falls under gravity from clouds. The main forms of precipitation include drizzle, rain, sleet, snow, graupel, and hail.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>27","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following elements of weather and climate is marched with the wrong measuring instrument?","images":[],"options":{"A":"Wind direction and wind vane","B":"Temperature and thermometer","C":"Humidity and barometer","D":"Rain and rainguage"},"answer":"C","explanation":"Humidity is measured with a hydrometer. It is atmospheric pressure measurement that we use the barometer for","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>28","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Through which of the following processes does solar energy warm the earth's surface?","images":[],"options":{"A":"Refraction","B":"Convection","C":"Conduction","D":"Radiation"},"answer":"D","explanation":"Solar energy warms the earth's surface through radiation. Radiation is the transfer of energy by electromagnetic waves. In this case, the sun's energy is transferred through space and then absorbed by the earth's surface, causing it to warm.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>29","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"The release of harmful substances into the environment is called","images":[],"options":{"A":"flooding","B":"drought","C":"harmattan","D":"pollution"},"answer":"D","explanation":"The release of harmful substances into the environment is referred to as pollution. Pollution can be in the form of air, water, soil, noise, light, or thermal. It involves the introduction of contaminants into the natural environment that cause adverse changes.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>30","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is the most important agent of erosion in humid regions?","images":[],"options":{"A":"Fog","B":"Wind","C":"Ice","D":"Running water"},"answer":"C","explanation":"Ice is the most important agent of denudation (erosion in humid regions)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>31","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The diagram below shows a hypothetical representation of population of selected countries in 2007, 2008 and 2009.   Use the diagram below to answer the question    The diagrammatic representation above is a","images":["data:image/png;base64,"],"options":{"A":"Venn diagram","B":"line graph","C":"pie chart","D":"bar graph"},"answer":"D","explanation":"The diagrammatic representation is a bar chart. Other options are not.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>32","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The population of Canada in 2008 is","images":["data:image/png;base64,"],"options":{"A":"190 million","B":"400 million","C":"650 million","D":"750 million"},"answer":"B","explanation":"The population of Canada in 2008 corresponds to 400 million on the vertical axis","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>33","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"By how much did the population of Germany grow between 2008 and 2009?","images":[],"options":{"A":"10 million","B":"50 million","C":"120 million","D":"400 million"},"answer":"B","explanation":"In 2018, the population of Germany was 50 million and in 2009, the population of Germany was 50 million; and in 2009, it grew to 100 million. Hence, the population of Germany grew by 50 million between 2008 and 2009.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>34","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Water pollution is caused by all the following except","images":[],"options":{"A":"treated sewage","B":"industrial waste","C":"oil spillage","D":"fishing with chemicals"},"answer":"A","explanation":"Treated sewage is not a cause of water pollution. Treated sewage refers to wastewater or sewage that has been treated and cleaned of pollutants and contaminants to a level that it can be safely discharged into the environment or reused. The other options, industrial waste, oil spillage, and fishing with chemicals, are all known causes of water pollution.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>35","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"\"The climate is constantly warm, rainfall is relatively abundant with double maxima, there is no month without rain.\" These are the characteristics of the","images":[],"options":{"A":"Monsoon climate","B":"Warm temperate climate","C":"Equitorial climate","D":"Mediterranean climate"},"answer":"C","explanation":"\"The climate is constantly warm, rainfall is relatively abundant with double maxima, there is no month without rain\",   these are characteristics of Equatorial climate","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>36","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following climatic type has the smallest annual range of temperature?","images":[],"options":{"A":"Cool temperate","B":"Warm temperate","C":"Tropical desert","D":"Equatorial"},"answer":"A","explanation":"Of the climatic types given (stated) in the options, cool temperate has the smallest annual range of temperature","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>37","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is the first stage in the process of lumbering?","images":[],"options":{"A":"Trees are cut into logs","B":"Suitable species are identified","C":"Trees are felled with power saw","D":"Platforms are built for buttress trees"},"answer":"B","explanation":"The first stage in the process of lumbering is identifying suitable species. Lumbering is the process of cutting down trees, processing them into logs and transporting them to a mill. Before any trees are cut down, it is important to identify the species that are suitable for the intended use. This is because different species of trees have different characteristics, such as hardness, grain, and moisture content, which can affect their suitability for different uses.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>38","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following criteria is not important in distinquishing between a village and a town?","images":[],"options":{"A":"Geographical situation","B":"Population size","C":"Social amenities","D":"Variety of activities"},"answer":"A","explanation":"The geographical situation is not an important criterion in distinguishing between a village and a town. The distinction between a village and a town is typically based on factors such as population size, the presence of social amenities, and the variety of activities. However, the geographical situation, such as whether the settlement is located in a rural or urban area, is not a definitive factor. For example, a settlement may be located in a rural area but still be considered a town due to its large population size and the presence of various social amenities and activities.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>39","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The number of persons per square kilometre of land is called","images":[],"options":{"A":"total population","B":"high population","C":"population density","D":"optimum population"},"answer":"C","explanation":"The number of persons per square kilometre of land is called population density. Population density is a measure of the number of people living in an area per unit of land, typically per square kilometre or square mile. It is used to compare the population distribution in different regions. The higher the population density, the more crowded the area is considered to be.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>40","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following is an advantage of high population density?","images":[],"options":{"A":"Unemployment","B":"employment","C":"Low crime rate","D":"Low pressure on social amenities"},"answer":"A","explanation":"High population density can be likened on to over population which infers that the population are more than the available resources and employment opportunities. Hence, high population density leads to unemployment.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>41","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which factor of industrial location explains the establishment of cement industries near areas of limestone deposit? Proximity to","images":[],"options":{"A":"power","B":"source of raw materials","C":"market","D":"income sources"},"answer":"B","explanation":"The major raw material needed for the manufacture of cement is limestone. Transporting limestone from the site of exploration to the cement manufacturing industry is always not convenient. Hence cement manufacturing industries are always sited close to the source of raw materials","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>42","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of the following mode of transportation provides door-to-door services?","images":[],"options":{"A":"Road transport","B":"Rail transport","C":"Ocean navigation","D":"Air transport"},"answer":"A","explanation":"Road transport provides door-to-door services. This is because vehicles can navigate through roads to reach specific addresses, unlike other modes of transport like rail, ocean navigation, and air transport which require terminals or stations. Therefore, road transport is the most flexible and convenient for door-to-door services.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>43","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"African rivers exhibit the following characteristics except","images":[],"options":{"A":"that they have their sources in the interior highlands.","B":"the presence of rapids and waterfalls on their courses","C":"that they exhibit seasonal variations in water volume","D":"that they have great depths"},"answer":"D","explanation":"African rivers are generally not known for their great depths. They are known for having their sources in the interior highlands, having rapids and waterfalls on their courses, and exhibiting seasonal variations in water volume due to the seasonal rainfall patterns in Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>44","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"What method of mining is used for extracting petroleum in Africa?","images":[],"options":{"A":"Crushing","B":"Drilling","C":"Adit","D":"Open cast"},"answer":"B","explanation":"Drilling is the method used for extracting petroleum. This involves drilling a hole into the earth's crust to reach the oil reservoirs. Crushing, Adit, and Open cast are methods used in mining solid minerals, not petroleum.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>45","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"What factor accounts for the slow rate of industrial development in Tropical Africa?","images":[],"options":{"A":"Inadequate capital","B":"Availability of essential social services","C":"Adequate skilled labour","D":"Modern technology"},"answer":"A","explanation":"Inadequate capital is a major factor which accounts for the slow rate of industrial development in Tropical area.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>46","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"What it the name of the local wind that blows in West Africa between November and February?","images":[],"options":{"A":"Harmattan","B":"Chinook","C":"Monsoon wind","D":"land breeze"},"answer":"A","explanation":"The Harmattan is a season in the West African subcontinent, which occurs between the end of November and the middle of March. It is characterized by the dry and dusty northeasterly trade wind, of the same name, which blows from the Sahara Desert over West Africa into the Gulf of Guinea.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2013>47","subject":"Geography","year":"2013","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following vegetation belts in Africa is the most extensive?","images":[],"options":{"A":"Mediterranean forest","B":"Temperate grassland","C":"Savannah","D":"Temperate forest"},"answer":"C","explanation":"The Savannah vegetation belt is the most extensive in Africa. It spans across many countries in Africa and is characterized by grasslands with scattered trees. This vegetation belt is found between the desert and the rainforest.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>48","subject":"Geography","year":"2013","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Through which of the following sea routes is crude oil from West Africa transported to European markets?","images":[],"options":{"A":"The Panama Canal route","B":"The cape route","C":"The Suez Canal route","D":"The North Atlantic route"},"answer":"D","explanation":"The North Atlantic route is usually utilized in the transportation of crude oil from West Africa to European markets","marks":"1","difficulty":"3"},{"id":"objective>Geography>2013>49","subject":"Geography","year":"2013","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following town has winter rainfall and summer drought?","images":[],"options":{"A":"Banjul","B":"Cape Town","C":"Lagos","D":"Accra"},"answer":"D","explanation":"In the options given, only Accra has winter and summer drought.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2013>50","subject":"Geography","year":"2013","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Favourable factors for lumbering in Africa include all the following except","images":[],"options":{"A":"high demand for tropical timber","B":"presence of many economic trees","C":"high demand for fuel wood","D":"inaccessible equatorial forest"},"answer":"D","explanation":"Inaccessible equatorial forest is not a favourable factor for lumbering in Africa. Lumbering requires accessibility to the forest for the extraction of timber. Dense and inaccessible forests make it difficult for lumbering activities to take place due to the challenges in transportation and extraction of the timber.","marks":"1","difficulty":"3"}];